import gurobipy as gp
from gurobipy import GRB

# Create a new model
model = gp.Model("LogisticsRouting")

# Shipments and their routes (hub, handling_time)
shipments = {
    'S1': [('H1', 7), ('H3', 1), ('H2', 10)],
    'S2': [('H2', 6), ('H3', 2), ('H1', 4)],
    'S3': [('H3', 3), ('H1', 9), ('H2', 8)]
}

# Hubs
hubs = ['H1', 'H2', 'H3']

# Decision Variables
x = {}  # Start time of shipment s at hub h
y = {}  # Precedence variable: y[s_i, s_j, h] = 1 if s_i is before s_j at hub h
C_max = model.addVar(vtype=GRB.CONTINUOUS, name="C_max")

# Initialize variables
for s in shipments:
    for h, _ in shipments[s]:
        x[(s, h)] = model.addVar(vtype=GRB.CONTINUOUS, name=f"x_{s}_{h}")

for h in hubs:
    for s_i in shipments:
        for s_j in shipments:
            if s_i != s_j:
                y[(s_i, s_j, h)] = model.addVar(vtype=GRB.BINARY, name=f"y_{s_i}_{s_j}_{h}")

# Objective: Minimize makespan
model.setObjective(C_max, GRB.MINIMIZE)

# Constraints
# 1. Sequence constraints for each shipment
for s in shipments:
    route = shipments[s]
    for k in range(len(route) - 1):
        h_curr, t_curr = route[k]
        h_next, _ = route[k + 1]
        model.addConstr(
            x[(s, h_next)] >= x[(s, h_curr)] + t_curr,
            name=f"seq_{s}_{h_curr}_{h_next}"
        )

# 2. Hub capacity constraints (no overlapping)
M = 1000  # Big-M constant
for h in hubs:
    for s_i in shipments:
        for s_j in shipments:
            if s_i != s_j and h in [hub for hub, _ in shipments[s_i]] and h in [hub for hub, _ in shipments[s_j]]:
                model.addConstr(
                    x[(s_i, h)] >= x[(s_j, h)] + [t for hub, t in shipments[s_j] if hub == h][0] - M * (1 - y[(s_i, s_j, h)]),
                    name=f"cap_{s_i}_{s_j}_{h}_1"
                )
                model.addConstr(
                    x[(s_j, h)] >= x[(s_i, h)] + [t for hub, t in shipments[s_i] if hub == h][0] - M * y[(s_i, s_j, h)],
                    name=f"cap_{s_i}_{s_j}_{h}_2"
                )

# 3. Makespan constraint
for s in shipments:
    last_hub, last_time = shipments[s][-1]
    model.addConstr(
        C_max >= x[(s, last_hub)] + last_time,
        name=f"makespan_{s}"
    )

# Solve the model
model.optimize()

# Print the solution
if model.status == GRB.OPTIMAL:
    print(f"Optimal total completion time (makespan): {C_max.x}")

    print("\nStart times for each shipment at each hub:")
    for s in shipments:
        print(f"\nShipment {s}:")
        for h, t in shipments[s]:
            print(f"  - Hub {h}: starts at {x[(s, h)].x}, handling time: {t}")

    print("\nPrecedence at hubs:")
    for h in hubs:
        print(f"\nHub {h}:")
        for s_i in shipments:
            for s_j in shipments:
                if s_i != s_j and (s_i, s_j, h) in y and y[(s_i, s_j, h)].x > 0.5:
                    print(f"  - {s_i} before {s_j}")
else:
    print("No optimal solution found.")

