import gurobipy as gp
from gurobipy import GRB

# Create a new model
model = gp.Model("Hub_Scheduling")

# Routes and their stages
routes = {
    1: [('C', 5), ('B', 5), ('A', 7), ('D', 7)],
    2: [('D', 4), ('A', 5), ('C', 6), ('B', 1)],
    3: [('A', 8), ('B', 10), ('C', 2), ('D', 3)],
    4: [('C', 7), ('B', 8), ('A', 1), ('D', 2)]
}

# Extract all stages and hubs
stages = {r: list(range(1, len(routes[r]) + 1)) for r in routes}
hubs = set(hub for r in routes for hub, _ in routes[r])

# Big-M (sum of all durations)
M = sum(duration for r in routes for _, duration in routes[r])

# Decision Variables
start = model.addVars(routes.keys(), stages[1], name="start")
end = model.addVars(routes.keys(), stages[1], name="end")
makespan = model.addVar(name="makespan")

# Binary variables for hub conflicts
y = model.addVars(
    [(r1, s1, r2, s2) for r1 in routes for s1 in stages[r1] 
     for r2 in routes for s2 in stages[r2] 
     if (r1, s1) != (r2, s2) and routes[r1][s1-1][0] == routes[r2][s2-1][0]],
    vtype=GRB.BINARY, name="y"
)

# Objective: Minimize makespan
model.setObjective(makespan, GRB.MINIMIZE)

# Constraints
# Stage sequence constraints
for r in routes:
    for s in stages[r][1:]:
        model.addConstr(
            start[r, s] >= end[r, s-1],
            f"sequence_{r}_{s}"
        )

# Duration constraints
for r in routes:
    for s in stages[r]:
        model.addConstr(
            end[r, s] == start[r, s] + routes[r][s-1][1],
            f"duration_{r}_{s}"
        )

# Hub capacity constraints
for r1 in routes:
    for s1 in stages[r1]:
        hub1 = routes[r1][s1-1][0]
        for r2 in routes:
            for s2 in stages[r2]:
                hub2 = routes[r2][s2-1][0]
                if (r1, s1) != (r2, s2) and hub1 == hub2:
                    model.addConstr(
                        start[r1, s1] >= end[r2, s2] - M * (1 - y[r1, s1, r2, s2]),
                        f"hub_capacity_{r1}_{s1}_{r2}_{s2}_1"
                    )
                    model.addConstr(
                        start[r2, s2] >= end[r1, s1] - M * y[r1, s1, r2, s2],
                        f"hub_capacity_{r1}_{s1}_{r2}_{s2}_2"
                    )

# Makespan definition
for r in routes:
    for s in stages[r]:
        model.addConstr(
            makespan >= end[r, s],
            f"makespan_{r}_{s}"
        )

# Solve the model
model.optimize()

# Print the solution
if model.status == GRB.OPTIMAL:
    print(f"Optimal Makespan: {makespan.X:.2f}")
    print("\nSchedule:")
    for r in routes:
        print(f"Route {r}:")
        for s in stages[r]:
            hub, duration = routes[r][s-1]
            print(f"  Stage {s} at Hub {hub}: Start = {start[r, s].X:.2f}, End = {end[r, s].X:.2f}")
else:
    print("No optimal solution found.")
